# --- Middleware for metrics collection ---


@app.before_request
def before_request_metrics():
    """Record request start time and increment in-progress gauge."""
    g.start_time = time.perf_counter()
    endpoint = _get_sanitized_endpoint()
    REQUESTS_IN_PROGRESS.labels(method=request.method, endpoint=endpoint).inc()

    # Track request size (just the size, not the content)
    request_size = request.content_length or 0
    REQUEST_SIZE.labels(method=request.method, endpoint=endpoint).observe(
        request_size
    )

    # Track auth method used (not the actual credentials)
    auth_method = "none"
    if request.headers.get("Authorization"):
        auth_header = request.headers.get("Authorization", "")
        if auth_header.startswith("Bearer "):
            auth_method = "bearer_token"
        elif auth_header.startswith("Basic "):
            auth_method = "basic"
        else:
            auth_method = "other"
    elif request.headers.get("X-API-Key"):
        auth_method = "api_key"

    if auth_method != "none":
        AUTH_REQUEST_COUNT.labels(
            method=request.method,
            endpoint=endpoint,
            auth_method=auth_method,
        ).inc()


@app.after_request
def after_request_metrics(response):
    """Record request duration and status code."""
    endpoint = _get_sanitized_endpoint()

    # Latency
    if hasattr(g, "start_time"):
        latency = time.perf_counter() - g.start_time
        REQUEST_LATENCY.labels(
            method=request.method, endpoint=endpoint
        ).observe(latency)

    # Request count by status
    REQUEST_COUNT.labels(
        method=request.method,
        endpoint=endpoint,
        status_code=response.status_code,
    ).inc()

    # Response size
    response_size = response.content_length or 0
    RESPONSE_SIZE.labels(method=request.method, endpoint=endpoint).observe(
        response_size
    )

    # Decrement in-progress
    REQUESTS_IN_PROGRESS.labels(
        method=request.method, endpoint=endpoint
    ).dec()

    # Track errors
    if response.status_code >= 400:
        error_type = _classify_error(response.status_code)
        ERROR_COUNT.labels(
            method=request.method,
            endpoint=endpoint,
            error_type=error_type,
        ).inc()

    return response


def _get_sanitized_endpoint():
    """
    Return a sanitized endpoint name to prevent cardinality explosion.

    Uses Flask's matched rule (e.g., '/users/<id>') rather than the actual
    path (e.g., '/users/12345') to keep label cardinality bounded.
    """
    if request.url_rule:
        return request.url_rule.rule
    # For unmatched routes, use a generic label (not the raw path,
    # which could contain user data and cause cardinality explosion)
    return "unmatched"


def _classify_error(status_code):
    """Classify HTTP error by category."""
    if status_code == 400:
        return "bad_request"
    elif status_code == 401:
        return "unauthorized"
    elif status_code == 403:
        return "forbidden"
    elif status_code == 404:
        return "not_found"
    elif status_code == 429:
        return "rate_limited"
    elif 400 <= status_code < 500:
        return "client_error"
    elif 500 <= status_code < 600:
        return "server_error"
    return "unknown"


